CODE_EXAMPLE:
public class OrderService {
  public decimal CalculateTotal(Order order) {
    decimal subtotal = 0;
    foreach (var item in order.Items) {
      subtotal += item.Price * item.Quantity;
    }
    decimal discount = subtotal > 100 ? subtotal * 0.1m : 0;
    return subtotal - discount;
  }

  public decimal CalculateSubtotal(Order order) {
    decimal subtotal = 0;
    foreach (var item in order.Items) subtotal += item.Price * item.Quantity;
    return subtotal;
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void CalculateSubtotal_ReturnsSumOfItems() {
  var order = new Order { Items = new List<OrderItem> { new OrderItem(10m, 2), new OrderItem(5m, 1) } };
  var service = new OrderService();
  Assert.AreEqual(25m, service.CalculateSubtotal(order));
}

[TestMethod]
public void CalculateTotal_AppliesDiscountForLargeSubtotal() {
  var order = new Order { Items = new List<OrderItem> { new OrderItem(60m, 2) } };
  var service = new OrderService();
  Assert.AreEqual(108m, service.CalculateTotal(order));
}
